def onToOff(panelValue):

	relativePathsMode = parent.Widget.par.Relativepaths.eval()

	try:
		fileTypes = tdu.split(parent.Widget.par.Fileextensionslist.eval())
	except:
		fileTypes = None

	currentValue = getattr(parent.Widget.par, 'Value'+str(panelValue.owner.digits)).eval()

	startFile = currentValue
	filePath = ui.chooseFile(load=bool(parent.Widget.par.Fileload.eval()),
		start=startFile,
		fileTypes=fileTypes,
		title='Select A File')

	if filePath:

		if relativePathsMode == 'Anywhere':
			try:
				filePath = os.path.relpath(filePath, project.folder)
			except:
				pass

		elif relativePathsMode == 'Project':
			isRelative = False
			paths = [os.path.normpath(project.folder), os.path.normpath(filePath)]
			try:
				commonPath = os.path.commonpath(paths)
			except:
				commonPath = None

			if commonPath and os.path.normpath(commonPath) == os.path.normpath(project.folder):
				try:
					filePath = os.path.relpath(filePath, project.folder)
					isRelative = True
				except:
					pass

		if parent.Widget.par.Useprojectpaths.eval():
			filePath = urlPath(filePath)

		setattr(parent.Widget.par, 'Value'+str(panelValue.owner.digits), filePath)

