def urlPath(ipath):
	"""
	If valid parent path is found in project.paths then a new path using the URL formatting 
	is returned - If nothing is found, None is returned
	"""
	#os.path.normpath(path)
	#ipath = PurePath(ipath)
	npaths = [(i[0], PurePath(os.path.normpath(i[1]))) for i in  project.paths.items()]
	ipath = PurePath(ipath)
	urlPath = ipath
	for n in npaths:
		#test = ipath.relative_to(n[1])
		#debug(test)
		try:
			ppath = ipath.relative_to(n[1])
		except:
			ppath = None

		if ppath:
			if ppath == PurePath('.'):
				urlPath = n[0] + '://'
			else:
				urlPath = n[0] + '://' + str(ppath).replace('\\', '/')

	return urlPath
